<template><div class="page-container enterprise-list-page"><div class="page-card page-flex-card compact-list-card enterprise-list-card"><div class="header"><div><h2>职位管理</h2><p>发布、编辑、上下架职位，修改后会重新进入管理员审核。</p></div><el-button type="primary" @click="open()">发布职位</el-button></div><el-divider/><el-form inline><el-form-item label="状态"><el-select v-model="query.status" clearable style="width:120px" @change="reload"><el-option label="招聘中" :value="1"/><el-option label="已下架" :value="0"/></el-select></el-form-item><el-form-item label="审核"><el-select v-model="query.auditStatus" clearable style="width:120px" @change="reload"><el-option label="待审核" :value="0"/><el-option label="通过" :value="1"/><el-option label="驳回" :value="2"/></el-select></el-form-item></el-form><el-table :data="list" stripe v-loading="loading"><el-table-column prop="title" label="岗位" min-width="180"/><el-table-column label="类型" width="90"><template #default="{row}"><el-tag>{{row.jobType===1?'全职':'实习'}}</el-tag></template></el-table-column><el-table-column label="薪资" width="120"><template #default="{row}"><span class="salary">{{row.salaryMin}}-{{row.salaryMax}}K</span></template></el-table-column><el-table-column prop="city" label="城市" width="100"/><el-table-column label="审核" width="110"><template #default="{row}"><el-tag :type="auditType(row.auditStatus)">{{['待审核','通过','驳回'][row.auditStatus]}}</el-tag></template></el-table-column><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="row.status===1?'success':'info'">{{row.status===1?'招聘中':'已下架'}}</el-tag></template></el-table-column><el-table-column label="数据" width="130"><template #default="{row}">浏览{{row.viewCount||0}}/投递{{row.applyCount||0}}</template></el-table-column><el-table-column label="操作" width="260"><template #default="{row}"><el-button text type="primary" @click="open(row)">编辑</el-button><el-button text @click="toggle(row)">{{row.status===1?'下架':'上架'}}</el-button><el-button text @click="refresh(row)">刷新</el-button><el-button text type="danger" @click="del(row)">删除</el-button></template></el-table-column></el-table><div class="pagination-wrap"><el-pagination v-model:current-page="query.pageNum" :total="total" background layout="total,prev,pager,next" @current-change="load"/></div></div><el-dialog v-model="dialog" :title="form.id?'编辑职位':'发布职位'" width="760px"><el-form :model="form" label-width="100px"><el-row :gutter="16"><el-col :span="12"><el-form-item label="岗位名称"><el-input v-model="form.title"/></el-form-item></el-col><el-col :span="12"><el-form-item label="工作城市"><el-input v-model="form.city"/></el-form-item></el-col><el-col :span="12"><el-form-item label="岗位类型"><el-radio-group v-model="form.jobType"><el-radio :value="1">全职</el-radio><el-radio :value="2">实习</el-radio></el-radio-group></el-form-item></el-col><el-col :span="12"><el-form-item label="招聘人数"><el-input-number v-model="form.recruitNum" :min="1"/></el-form-item></el-col><el-col :span="12"><el-form-item label="最低薪资K"><el-input-number v-model="form.salaryMin" :min="0"/></el-form-item></el-col><el-col :span="12"><el-form-item label="最高薪资K"><el-input-number v-model="form.salaryMax" :min="0"/></el-form-item></el-col><el-col :span="12"><el-form-item label="学历要求"><el-input v-model="form.education"/></el-form-item></el-col><el-col :span="12"><el-form-item label="专业要求"><el-input v-model="form.majorRequire"/></el-form-item></el-col><el-col :span="24"><el-form-item label="福利标签"><el-input v-model="form.welfare" placeholder="五险一金,年终奖"/></el-form-item></el-col><el-col :span="24"><el-form-item label="岗位职责"><el-input v-model="form.duty" type="textarea" :rows="4"/></el-form-item></el-col><el-col :span="24"><el-form-item label="任职要求"><el-input v-model="form.requirement" type="textarea" :rows="4"/></el-form-item></el-col></el-row></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{reactive,ref,onMounted}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{enterpriseApi}from'@/api';const query=reactive({pageNum:1,pageSize:10,status:'',auditStatus:''});const list=ref([]),total=ref(0),loading=ref(false),dialog=ref(false);const form=reactive({});const auditType=s=>s===1?'success':s===2?'danger':'warning';const load=async()=>{loading.value=true;try{const p={pageNum:query.pageNum,pageSize:query.pageSize};if(query.status!=='')p.status=query.status;if(query.auditStatus!=='')p.auditStatus=query.auditStatus;const r=await enterpriseApi.jobList(p);list.value=r.data.records;total.value=Number(r.data.total)}finally{loading.value=false}};const reload=()=>{query.pageNum=1;load()};const open=row=>{Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,row||{jobType:1,recruitNum:1,salaryMin:8,salaryMax:15,status:1});dialog.value=true};const save=async()=>{form.id?await enterpriseApi.updateJob(form):await enterpriseApi.saveJob(form);ElMessage.success('保存成功');dialog.value=false;load()};const toggle=row=>ElMessageBox.confirm(`确定${row.status===1?'下架':'上架'}该职位？`).then(async()=>{await enterpriseApi.toggleJob(row.id,row.status===1?0:1);ElMessage.success('操作成功');load()});const refresh=async row=>{await enterpriseApi.refreshJob(row.id);ElMessage.success('刷新成功');load()};const del=row=>ElMessageBox.confirm(`删除职位「${row.title}」？`).then(async()=>{await enterpriseApi.delJob(row.id);ElMessage.success('删除成功');load()});onMounted(load)</script>
<style scoped>.header{display:flex;justify-content:space-between;align-items:center}.header h2{margin-bottom:6px}.header p{color:var(--cr-text-muted)}.salary{color:var(--cr-danger);font-weight:600}</style>
